import { useState, useEffect, useCallback, useRef } from 'react';
import { Search, Users, LayoutGrid, FileText, X, Command, CornerDownLeft, User, ChevronRight } from 'lucide-react';
import { globalSearch } from '../../services/searchService';
import { useNavigate } from 'react-router-dom';
import clsx from 'clsx';
import Avatar from '../ui/Avatar';

const CommandPalette = ({ isOpen, onClose }) => {
    const [query, setQuery] = useState('');
    const [results, setResults] = useState({ users: [], communities: [], resources: [] });
    const [loading, setLoading] = useState(false);
    const [selectedIndex, setSelectedIndex] = useState(0);
    const navigate = useNavigate();
    const inputRef = useRef(null);

    // Flatten results for keyboard navigation
    const flatResults = [
        ...results.users.map(u => ({ ...u, type: 'user' })),
        ...results.communities.map(c => ({ ...c, type: 'community' })),
        ...results.resources.map(r => ({ ...r, type: 'resource' }))
    ];

    const handleSearch = useCallback(async (q) => {
        if (!q.trim()) {
            setResults({ users: [], communities: [], resources: [] });
            return;
        }
        setLoading(true);
        try {
            const response = await globalSearch(q);
            setResults(response.data.data);
            setSelectedIndex(0);
        } catch (error) {
            console.error('Search failed', error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        const timer = setTimeout(() => {
            handleSearch(query);
        }, 300);
        return () => clearTimeout(timer);
    }, [query, handleSearch]);

    useEffect(() => {
        if (isOpen) {
            setQuery('');
            setSelectedIndex(0);
            setTimeout(() => inputRef.current?.focus(), 100);
        }
    }, [isOpen]);

    const handleSelect = (item) => {
        if (!item) return;
        onClose();
        if (item.type === 'user') navigate(`/u/${item._id}`);
        if (item.type === 'community') navigate(`/r/${item.name}`);
        if (item.type === 'resource') window.open(item.url, '_blank');
    };

    const onKeyDown = (e) => {
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            setSelectedIndex(prev => (prev + 1) % Math.max(flatResults.length, 1));
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            setSelectedIndex(prev => (prev - 1 + flatResults.length) % Math.max(flatResults.length, 1));
        } else if (e.key === 'Enter') {
            e.preventDefault();
            handleSelect(flatResults[selectedIndex]);
        } else if (e.key === 'Escape') {
            onClose();
        }
    };

    if (!isOpen) return null;

    return (
        <div 
            className="fixed inset-0 z-[100] flex items-start justify-center pt-[15vh] px-4 bg-dark-900/40 backdrop-blur-sm animate-in fade-in duration-300"
            onClick={onClose}
        >
            <div 
                className="w-full max-w-2xl bg-dark-800/80 backdrop-blur-2xl border border-white/5 rounded-[2.5rem] shadow-premium overflow-hidden animate-in zoom-in-95 slide-in-from-top-4 duration-300"
                onClick={e => e.stopPropagation()}
                onKeyDown={onKeyDown}
            >
                {/* Search Input Area */}
                <div className="relative p-6 border-b border-white/5">
                    <Search className={clsx(
                        "absolute left-10 top-1/2 -translate-y-1/2 w-5 h-5 transition-colors duration-300",
                        loading ? "text-primary animate-pulse" : "text-gray-500"
                    )} />
                    <input
                        ref={inputRef}
                        type="text"
                        placeholder="Search for people, communities, or resources..."
                        className="w-full bg-white/5 border border-white/5 rounded-2xl pl-14 pr-12 py-5 text-sm font-black text-white placeholder-gray-500 focus:outline-none focus:ring-4 focus:ring-primary/5 transition-all"
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                    />
                    <div className="absolute right-10 top-1/2 -translate-y-1/2 flex items-center gap-2">
                        <div className="px-2 py-1 rounded bg-white/5 border border-white/5 text-[9px] font-black text-gray-500 flex items-center gap-1">
                            <span className="text-[11px]">ESC</span>
                        </div>
                    </div>
                </div>

                {/* Results Section */}
                <div className="max-h-[60vh] overflow-y-auto p-4 custom-scrollbar">
                    {!query ? (
                        <div className="py-12 text-center space-y-4">
                            <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto border border-white/5">
                                <Command className="w-8 h-8 text-gray-600" />
                            </div>
                            <div className="space-y-1">
                                <p className="text-sm font-black text-gray-400">Search Anything</p>
                                <p className="text-xs text-gray-600">Communities, Students, Alumni, and Library Files</p>
                            </div>
                        </div>
                    ) : flatResults.length > 0 ? (
                        <div className="space-y-6">
                            {/* Users Section */}
                            {results.users.length > 0 && (
                                <div>
                                    <h3 className="px-4 mb-2 text-[10px] font-black text-gray-500 uppercase tracking-widest flex items-center gap-2">
                                        <User className="w-3 h-3" /> People
                                    </h3>
                                    <div className="space-y-1">
                                        {results.users.map((item, idx) => (
                                            <ResultItem 
                                                key={item._id}
                                                item={{...item, type: 'user'}}
                                                isSelected={flatResults[selectedIndex]?._id === item._id}
                                                onClick={() => handleSelect({...item, type: 'user'})}
                                            />
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Communities Section */}
                            {results.communities.length > 0 && (
                                <div>
                                    <h3 className="px-4 mb-2 text-[10px] font-black text-gray-500 uppercase tracking-widest flex items-center gap-2">
                                        <LayoutGrid className="w-3 h-3" /> Communities
                                    </h3>
                                    <div className="space-y-1">
                                        {results.communities.map((item) => (
                                            <ResultItem 
                                                key={item._id}
                                                item={{...item, type: 'community'}}
                                                isSelected={flatResults[selectedIndex]?._id === item._id}
                                                onClick={() => handleSelect({...item, type: 'community'})}
                                            />
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Resources Section */}
                            {results.resources.length > 0 && (
                                <div>
                                    <h3 className="px-4 mb-2 text-[10px] font-black text-gray-500 uppercase tracking-widest flex items-center gap-2">
                                        <FileText className="w-3 h-3" /> Files & Docs
                                    </h3>
                                    <div className="space-y-1">
                                        {results.resources.map((item) => (
                                            <ResultItem 
                                                key={item._id}
                                                item={{...item, type: 'resource'}}
                                                isSelected={flatResults[selectedIndex]?._id === item._id}
                                                onClick={() => handleSelect({...item, type: 'resource'})}
                                            />
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    ) : !loading && (
                        <div className="py-12 text-center">
                            <p className="text-sm font-black text-gray-600 italic">No matches found for "{query}"</p>
                        </div>
                    )}
                </div>

                {/* Footer / Shortcuts */}
                <div className="p-4 bg-white/5 border-t border-white/5 flex items-center justify-between">
                    <div className="flex items-center gap-4 text-[10px] font-black text-gray-500 uppercase tracking-tighter">
                        <div className="flex items-center gap-1.5"><ChevronRight className="w-3 h-3" /> Navigate</div>
                        <div className="flex items-center gap-1.5"><CornerDownLeft className="w-3 h-3" /> Open</div>
                    </div>
                    <div className="text-[10px] font-black text-primary/40 uppercase tracking-widest italic">
                        Command Palette v1.0
                    </div>
                </div>
            </div>
        </div>
    );
};

const ResultItem = ({ item, isSelected, onClick }) => {
    return (
        <button
            onClick={onClick}
            onMouseEnter={() => {}} // Could sync select index here
            className={clsx(
                "w-full flex items-center justify-between p-3 rounded-2xl transition-all duration-200 group",
                isSelected ? "bg-primary text-white shadow-premium" : "hover:bg-white/5"
            )}
        >
            <div className="flex items-center gap-4 min-w-0">
                <div className="relative flex-shrink-0">
                    {item.type === 'user' ? (
                        <Avatar src={item.avatar} size="md" className={clsx("border-2", isSelected ? "border-white/20" : "border-white/5")} />
                    ) : item.type === 'community' ? (
                        <div className={clsx("w-10 h-10 rounded-xl flex items-center justify-center border-2", isSelected ? "bg-white/20 border-white/20" : "bg-dark-900 border-white/5")}>
                            <LayoutGrid className="w-5 h-5" />
                        </div>
                    ) : (
                        <div className={clsx("w-10 h-10 rounded-xl flex items-center justify-center border-2", isSelected ? "bg-white/20 border-white/20" : "bg-dark-900 border-white/5")}>
                            <FileText className="w-5 h-5" />
                        </div>
                    )}
                </div>
                <div className="text-left min-w-0">
                    <p className={clsx("text-sm font-black truncate", isSelected ? "text-white" : "text-gray-200")}>
                        {item.type === 'resource' ? item.title : item.name || item.displayName}
                    </p>
                    <p className={clsx("text-[10px] font-bold truncate opacity-60", isSelected ? "text-white" : "text-gray-500")}>
                        {item.type === 'user' ? item.college : 
                         item.type === 'community' ? `${item.memberCount || 0} members • ${item.college}` :
                         `${item.category} • Shared by ${item.author?.name}`}
                    </p>
                </div>
            </div>
            {isSelected && <CornerDownLeft className="w-4 h-4 text-white/40 animate-pulse flex-shrink-0" />}
        </button>
    );
};

export default CommandPalette;

import Avatar from '../ui/Avatar';
import { useState, useEffect } from 'react';
import { formatDistanceToNow } from 'date-fns';
import Button from '../ui/Button';
import Badge from '../ui/Badge';
import api from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import { toast } from 'react-hot-toast';
import { ArrowBigUp, ArrowBigDown, MessageCircle } from 'lucide-react';
import clsx from 'clsx';

const CommentItem = ({ comment, postId, onReplySuccess }) => {
    const { user } = useAuth();
    const [replying, setReplying] = useState(false);
    const [replyContent, setReplyContent] = useState("");
    const [voteState, setVoteState] = useState(comment.userVote || 0); // 1, -1, 0
    const [score, setScore] = useState(comment.score || 0);

    const handleVote = async (type) => { // 'up' or 'down'
        if (!user) return toast.error('Please login to vote');

        const value = type === 'up' ? 1 : -1;
        let newVoteState = value;
        let scoreChange = 0;

        if (voteState === value) {
            newVoteState = 0; // toggle off
            scoreChange = -1 * value;
        } else {
            scoreChange = value - voteState;
        }

        // Optimistic update
        setVoteState(newVoteState);
        setScore(prev => prev + scoreChange);

        try {
            if (newVoteState === 0) {
                await api.delete(`/comments/${comment._id}/vote`);
            } else {
                await api.post(`/comments/${comment._id}/vote`, { value: newVoteState });
            }
        } catch (error) {
            console.error('Vote failed', error);
            // Revert
            setVoteState(voteState);
            setScore(score);
        }
    };

    const handleReplySubmit = async (e) => {
        e.preventDefault();
        if (!replyContent.trim()) return;

        try {
            await api.post(`/posts/${postId}/comments`, {
                content: replyContent,
                parentId: comment._id
            });
            toast.success('Reply added');
            setReplying(false);
            setReplyContent("");
            if (onReplySuccess) onReplySuccess();
        } catch (error) {
            toast.error('Failed to reply');
        }
    };

    return (
        <div className="flex gap-3">
            <div className="flex flex-col items-center">
                <Avatar src={comment.author.avatar} size="sm" />
                <div className="h-full w-0.5 bg-dark-700 my-2 rounded-full" />
            </div>

            <div className="flex-1 pb-4">
                <div className="flex items-center gap-2 mb-1.5 flex-wrap">
                    <span className="text-xs font-black text-white/90">u/{comment.author.name}</span>

                    {comment.author.role === 'alumni' ? (
                        <Badge variant="alumni" verified className="scale-90 origin-left">
                            Alumni {comment.author.graduationYear ? `'${String(comment.author.graduationYear).slice(-2)}` : ''}
                        </Badge>
                    ) : comment.author.year && (
                        <Badge variant="student" className="scale-90 origin-left">
                            {comment.author.year === 1 ? 'Freshman' : 
                             comment.author.year === 2 ? 'Sophomore' : 
                             comment.author.year === 3 ? 'Junior' : 'Senior'}
                        </Badge>
                    )}

                    <span className="text-[10px] text-gray-500 font-medium ml-1">
                        {formatDistanceToNow(new Date(comment.createdAt), { addSuffix: true })}
                    </span>
                </div>
                <p className="text-sm text-gray-300 leading-relaxed">{comment.content}</p>

                <div className="flex items-center gap-4 mt-2">
                    <div className="flex items-center gap-1">
                        <button
                            onClick={() => handleVote('up')}
                            className={clsx("p-0.5 rounded hover:bg-dark-700 text-gray-400", voteState === 1 && "text-primary")}
                        >
                            <ArrowBigUp className={clsx("w-5 h-5", voteState === 1 && "fill-current")} />
                        </button>
                        <span className={clsx("text-xs font-bold",
                            voteState === 1 ? "text-primary" : voteState === -1 ? "text-blue-500" : "text-gray-400"
                        )}>{score}</span>
                        <button
                            onClick={() => handleVote('down')}
                            className={clsx("p-0.5 rounded hover:bg-dark-700 text-gray-400", voteState === -1 && "text-blue-500")}
                        >
                            <ArrowBigDown className={clsx("w-5 h-5", voteState === -1 && "fill-current")} />
                        </button>
                    </div>

                    <button
                        className="text-xs font-bold text-gray-400 hover:text-gray-300"
                        onClick={() => setReplying(!replying)}
                    >
                        Reply
                    </button>
                </div>

                {replying && (
                    <form onSubmit={handleReplySubmit} className="mt-4 flex flex-col gap-3 bg-dark-950/30 p-3 rounded-2xl border border-white/5 shadow-inner">
                        <textarea
                            value={replyContent}
                            onChange={(e) => setReplyContent(e.target.value)}
                            placeholder="Write your reply..."
                            className="w-full bg-transparent text-sm text-gray-200 focus:outline-none resize-none h-24"
                            autoFocus
                        />
                        <div className="flex justify-end gap-2 pr-1 pb-1">
                            <Button type="button" variant="ghost" size="sm" onClick={() => setReplying(false)}>Cancel</Button>
                            <Button type="submit" size="sm" className="px-6" disabled={!replyContent.trim()}>Reply</Button>
                        </div>
                    </form>
                )}

                {/* Nested Replies (recursively only if populated) */}
                {comment.replies && comment.replies.length > 0 && (
                    <div className="space-y-4 mt-4">
                        {comment.replies.map(reply => (
                            <CommentItem
                                key={reply._id}
                                comment={reply}
                                postId={postId}
                                onReplySuccess={onReplySuccess}
                            />
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};

const CommentSection = ({ postId }) => {
    const { user } = useAuth();
    const [comments, setComments] = useState([]);
    const [newComment, setNewComment] = useState("");
    const [loading, setLoading] = useState(true);

    const fetchComments = async () => {
        try {
            const response = await api.get(`/posts/${postId}/comments`);
            setComments(response.data.data.comments);
        } catch (error) {
            console.error('Failed to load comments', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchComments();
    }, [postId]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!newComment.trim()) return;
        if (!user) return toast.error('Please login to comment');

        try {
            await api.post(`/posts/${postId}/comments`, { content: newComment });
            setNewComment("");
            toast.success('Comment added');
            fetchComments(); // Refresh to show new comment
        } catch (error) {
            toast.error('Failed to post comment');
        }
    };

    return (
        <div className="mt-4 pt-4 border-t border-dark-600">
            <form onSubmit={handleSubmit} className="mb-6 flex gap-3">
                <Avatar src={user?.avatar} size="sm" />
                <div className="flex-1">
                    <textarea
                        value={newComment}
                        onChange={(e) => setNewComment(e.target.value)}
                        placeholder="What are your thoughts?"
                        className="w-full bg-dark-700 border border-dark-600 rounded-lg p-2 text-sm text-gray-200 focus:outline-none focus:border-gray-500 resize-none h-20"
                    />
                    <div className="flex justify-end mt-2">
                        <Button type="submit" size="sm" disabled={!newComment.trim()}>Comment</Button>
                    </div>
                </div>
            </form>

            <div className="space-y-4">
                {loading ? (
                    <p className="text-gray-500 text-center">Loading comments...</p>
                ) : comments.length > 0 ? (
                    comments.map(comment => (
                        <CommentItem
                            key={comment._id}
                            comment={comment}
                            postId={postId}
                            onReplySuccess={fetchComments}
                        />
                    ))
                ) : (
                    <p className="text-gray-500 text-center">No comments yet.</p>
                )}
            </div>
        </div>
    );
};

export default CommentSection;

import { useState, useRef } from 'react';
import Modal from '../ui/Modal';
import Input from '../ui/Input';
import Button from '../ui/Button';
import { toast } from 'react-hot-toast';
import { createResource, uploadResourceFile } from '../../services/resourceService';
import { UploadCloud, Link as LinkIcon, FileText } from 'lucide-react';
import clsx from 'clsx';

const AddResourceModal = ({ isOpen, onClose, onSuccess }) => {
    const [loading, setLoading] = useState(false);
    const [uploadType, setUploadType] = useState('link'); // 'link' or 'file'
    const [selectedFile, setSelectedFile] = useState(null);
    const fileInputRef = useRef(null);
    const [formData, setFormData] = useState({
        title: '',
        description: '',
        category: 'notes',
        url: '',
        tags: ''
    });

    const resetForm = () => {
        setFormData({ title: '', description: '', category: 'notes', url: '', tags: '' });
        setSelectedFile(null);
        setUploadType('link');
    };

    const handleFileChange = (e) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            const allowedTypes = ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'application/vnd.ms-powerpoint', 'application/vnd.openxmlformats-officedocument.presentationml.presentation'];

            if (!allowedTypes.includes(file.type)) {
                return toast.error('Format not supported. Please upload PDF, DOC, DOCX, PPT, or PPTX.');
            }
            if (file.size > 10 * 1024 * 1024) {
                return toast.error('File size should be less than 10MB.');
            }
            setSelectedFile(file);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.title) return toast.error('Please provide a title');
        if (!formData.description) return toast.error('Please provide a description');
        if (uploadType === 'link' && !formData.url) return toast.error('Please provide a resource link');
        if (uploadType === 'file' && !selectedFile) return toast.error('Please select a file to upload');

        setLoading(true);
        try {
            let finalUrl = formData.url;

            if (uploadType === 'file') {
                const uploadRes = await uploadResourceFile(selectedFile);
                finalUrl = uploadRes.data.data.url;
            }

            const tagsArray = formData.tags.split(',').map(tag => tag.trim()).filter(tag => tag !== '');
            await createResource({
                ...formData,
                url: finalUrl,
                tags: tagsArray
            });

            toast.success('Resource shared successfully!');
            onSuccess();
            resetForm();
            onClose();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to share resource');
        } finally {
            setLoading(false);
        }
    };

    const handleClose = () => {
        resetForm();
        onClose();
    };

    return (
        <Modal 
            isOpen={isOpen} 
            onClose={handleClose} 
            title="Share Academic Resource"
            className="max-w-md bg-dark-900 border-white/10"
        >
            <form onSubmit={handleSubmit} className="space-y-5 py-2">
                <div>
                    <label className="block text-[11px] font-black text-gray-500 uppercase tracking-widest mb-2 ml-1">Title *</label>
                    <Input 
                        placeholder="e.g. CS101 Midterm Notes" 
                        value={formData.title}
                        onChange={(e) => setFormData({...formData, title: e.target.value})}
                        required
                    />
                </div>

                <div>
                    <label className="block text-[11px] font-black text-gray-500 uppercase tracking-widest mb-2 ml-1">Category</label>
                    <select 
                        className="w-full bg-dark-800 border border-white/5 rounded-2xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-primary/40 focus:ring-4 focus:ring-primary/5 transition-all"
                        value={formData.category}
                        onChange={(e) => setFormData({...formData, category: e.target.value})}
                    >
                        <option value="notes">Notes</option>
                        <option value="exam-paper">Exam Paper</option>
                        <option value="book">Book</option>
                        <option value="link">Link/Tool</option>
                        <option value="other">Other</option>
                    </select>
                </div>

                <div>
                    <div className="flex items-center justify-between mb-2 ml-1">
                        <label className="text-[11px] font-black text-gray-500 uppercase tracking-widest">Resource Source *</label>
                        <div className="flex bg-dark-800 p-1 rounded-xl">
                            <button
                                type="button"
                                onClick={() => setUploadType('link')}
                                className={clsx(
                                    "px-3 py-1 text-xs font-bold rounded-lg transition-all flex items-center gap-1.5",
                                    uploadType === 'link' ? "bg-white/10 text-white" : "text-gray-500 hover:text-gray-300"
                                )}
                            >
                                <LinkIcon className="w-3 h-3" /> Link
                            </button>
                            <button
                                type="button"
                                onClick={() => setUploadType('file')}
                                className={clsx(
                                    "px-3 py-1 text-xs font-bold rounded-lg transition-all flex items-center gap-1.5",
                                    uploadType === 'file' ? "bg-white/10 text-white" : "text-gray-500 hover:text-gray-300"
                                )}
                            >
                                <UploadCloud className="w-3 h-3" /> Upload
                            </button>
                        </div>
                    </div>

                    {uploadType === 'link' ? (
                        <Input 
                            placeholder="Google Drive, Dropbox, or Website URL" 
                            value={formData.url}
                            onChange={(e) => setFormData({...formData, url: e.target.value})}
                            required={uploadType === 'link'}
                        />
                    ) : (
                        <div 
                            className={clsx(
                                "w-full border-2 border-dashed rounded-2xl p-6 flex flex-col items-center justify-center transition-all cursor-pointer group",
                                selectedFile ? "border-primary/50 bg-primary/5" : "border-white/10 bg-dark-800 hover:bg-dark-800/80 hover:border-white/20"
                            )}
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <input 
                                type="file"
                                ref={fileInputRef}
                                className="hidden"
                                accept=".pdf,.doc,.docx,.ppt,.pptx"
                                onChange={handleFileChange}
                            />
                            {selectedFile ? (
                                <div className="flex flex-col items-center space-y-2 text-center">
                                    <div className="w-10 h-10 bg-primary/20 rounded-full flex items-center justify-center text-primary">
                                        <FileText className="w-5 h-5" />
                                    </div>
                                    <div>
                                        <p className="text-sm font-bold text-gray-200 truncate max-w-[200px]">{selectedFile.name}</p>
                                        <p className="text-xs font-medium text-gray-500">{(selectedFile.size / (1024 * 1024)).toFixed(2)} MB</p>
                                    </div>
                                    <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-2 hover:text-white transition-colors">Click to change</p>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center space-y-2 text-center">
                                    <div className="w-10 h-10 bg-dark-700 rounded-full flex items-center justify-center text-gray-400 group-hover:text-white transition-colors">
                                        <UploadCloud className="w-5 h-5" />
                                    </div>
                                    <div>
                                        <p className="text-sm font-bold text-gray-300">Click to upload document</p>
                                        <p className="text-xs font-medium text-gray-500">PDF, DOC, DOCX, PPT (Max 10MB)</p>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <div>
                    <label className="block text-[11px] font-black text-gray-500 uppercase tracking-widest mb-2 ml-1">Description *</label>
                    <textarea 
                        className="w-full bg-dark-800 border border-white/5 rounded-2xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-primary/40 focus:ring-4 focus:ring-primary/5 transition-all min-h-[100px] resize-none"
                        placeholder="What's inside this resource?"
                        value={formData.description}
                        onChange={(e) => setFormData({...formData, description: e.target.value})}
                        required
                    />
                </div>

                <div>
                    <label className="block text-[11px] font-black text-gray-500 uppercase tracking-widest mb-2 ml-1">Tags (comma separated)</label>
                    <Input 
                        placeholder="e.g. semester1, computer-science, python" 
                        value={formData.tags}
                        onChange={(e) => setFormData({...formData, tags: e.target.value})}
                    />
                </div>

                <div className="pt-2 flex gap-3">
                    <Button type="button" variant="ghost" className="flex-1" onClick={handleClose}>Cancel</Button>
                    <Button type="submit" className="flex-1" loading={loading}>Share Resource</Button>
                </div>
            </form>
        </Modal>
    );
};

export default AddResourceModal;

import { useState, useEffect, useRef } from 'react';
import { Search, Bell, MessageSquare, Plus, Menu, Users, Hash, FileText, Loader2 } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { Link, useNavigate } from 'react-router-dom';
import { getImageUrl } from '../utils/imageUrl';
import { globalSearch } from '../services/searchService';
import { motion, AnimatePresence } from 'framer-motion';

const Navbar = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchQuery, setSearchQuery] = useState('');
    const [searchResults, setSearchResults] = useState(null);
    const [isSearching, setIsSearching] = useState(false);
    const [showDropdown, setShowDropdown] = useState(false);
    const dropdownRef = useRef(null);

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
                setShowDropdown(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        const delayDebounceFn = setTimeout(async () => {
            if (searchQuery.trim().length > 1) {
                setIsSearching(true);
                setShowDropdown(true);
                try {
                    const res = await globalSearch(searchQuery);
                    setSearchResults(res.data.data);
                } catch (error) {
                    console.error('Search error:', error);
                } finally {
                    setIsSearching(false);
                }
            } else {
                setSearchResults(null);
                setShowDropdown(false);
            }
        }, 300);

        return () => clearTimeout(delayDebounceFn);
    }, [searchQuery]);

    const handleResultClick = (path) => {
        navigate(path);
        setShowDropdown(false);
        setSearchQuery('');
    };

    return (
        <nav className="sticky top-0 z-50 glass-panel h-14 px-4 flex items-center justify-between border-b border-white/5">
            {/* Left: Logo */}
            <div className="flex items-center gap-4">
                <button className="md:hidden text-gray-400 hover:text-white transition-colors">
                    <Menu className="w-6 h-6" />
                </button>
                <Link to="/" className="flex items-center gap-2 group transition-all">
                    <div className="w-8 h-8 bg-primary rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-orange-glow group-hover:scale-105 transition-transform">
