      data: null
    })
  );
});

/**
 * Apply to job
 * POST /api/jobs/:id/apply
 */
export const applyToJob = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const userId = req.userId;
  const { coverLetter } = req.body;

  const job = await Job.findById(id);

  if (!job) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Job not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  // Check if job is active and not expired
  if (!job.isActive || job.isExpired) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'This job is no longer accepting applications',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Check if already applied
  if (job.hasApplied(userId)) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'You have already applied to this job',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Handle resume upload
  let resumeUrl = null;
  if (req.file) {
    resumeUrl = getFileUrl(req.file.filename);
  } else if (req.body.resume) {
    resumeUrl = req.body.resume;
  } else {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'Resume is required',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Add application
  const application = {
    applicant: userId,
    resume: resumeUrl,
    coverLetter,
    appliedAt: new Date()
  };

  const added = job.addApplication(application);

  if (!added) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'Failed to submit application',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  await job.save();

  res.status(HTTP_STATUS.CREATED).json(
    formatSuccess({
      message: 'Application submitted successfully',
      data: { application: job.applications[job.applications.length - 1] }
    })
  );
});

