import { Send, Smile, Paperclip, MoreVertical } from 'lucide-react';
import Avatar from '../ui/Avatar';
import MessageBubble from './MessageBubble';
import { useState, useEffect, useRef } from 'react';
import api from '../../services/api';
import { useSocket } from '../../context/SocketContext';
import { useAuth } from '../../context/AuthContext';

const ChatWindow = ({ chatId }) => {
    const { user: currentUser } = useAuth();
    const { socket } = useSocket();
    const [messages, setMessages] = useState([]);
    const [newMessage, setNewMessage] = useState("");
    const [chatUser, setChatUser] = useState(null);
    const [loading, setLoading] = useState(false);
    const messagesEndRef = useRef(null);

    // Fetch Chat User Details
    useEffect(() => {
        const fetchUser = async () => {
            if (!chatId) return;
            try {
                const response = await api.get(`/users/${chatId}`);
                setChatUser(response.data.data.user);
            } catch (error) {
                console.error('Failed to load user', error);
            }
        };
        fetchUser();
    }, [chatId]);

    // Fetch Messages
    useEffect(() => {
        const fetchMessages = async () => {
            if (!chatId) return;
            setLoading(true);
            try {
                const response = await api.get(`/chat/messages/${chatId}`);
                setMessages(response.data.data.messages.reverse()); // Backend returns newest first usually, depending on logic
            } catch (error) {
                console.error('Failed to load messages', error);
            } finally {
                setLoading(false);
            }
        };
        fetchMessages();
    }, [chatId]);

    // Join Room & Listen for Messages
    useEffect(() => {
        if (!socket || !chatId) return;

        socket.emit('join_conversation', { userId: chatId });

        const handleNewMessage = (data) => {
            // Check if message belongs to current conversation
            // Check if sender is chatId OR sender is currentUser (echo)
            // But we append optimistically or via response?
            // If sender is ME, I might have already added it.
            // The backend emits 'new_message' to the room.
            const msg = data.message;
            if (msg.sender._id === chatId || msg.sender._id === currentUser._id) {
                setMessages(prev => {
                    // Avoid duplicates
                    if (prev.some(m => m._id === msg._id || m.id === msg.id)) return prev;
                    return [...prev, msg];
                });
                scrollToBottom();
            }
        };

        socket.on('new_message', handleNewMessage);

        return () => {
            socket.emit('leave_conversation', { userId: chatId });
            socket.off('new_message', handleNewMessage);
        };
    }, [socket, chatId, currentUser]);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSend = async (e) => {
        e.preventDefault();
        if (!newMessage.trim() || !chatId) return;

        const content = newMessage;
        setNewMessage("");

        try {
            await api.post(`/chat/messages/${chatId}`, { content });
            // The backend will emit 'new_message' via socket, which we listen to
            // Or we can optimistically add it here
        } catch (error) {
            console.error('Failed to send message', error);
        }
    };

    if (!chatId) return <div className="flex-1 flex items-center justify-center text-gray-500">Select a chat</div>;

    return (
        <div className="flex-1 flex flex-col h-full bg-dark-900">
            {/* Header */}
            <div className="p-4 border-b border-dark-600 flex items-center justify-between bg-dark-800">
                <div className="flex items-center gap-3">
                    {chatUser && <Avatar src={chatUser.avatar} />}
                    <div>
                        <h3 className="font-bold text-gray-200">{chatUser ? chatUser.name : 'Loading...'}</h3>
                        {/* Online status placeholder */}
                        {/* <span className="text-xs text-green-500 flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full bg-green-500"></span> Online
                        </span> */}
                    </div>
                </div>
                <button className="text-gray-400 hover:text-gray-200"><MoreVertical className="w-5 h-5" /></button>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {loading ? <div className="text-center text-gray-500">Loading messages...</div> : (
                    messages.map(msg => {
                        const senderId = typeof msg.sender === 'object' ? msg.sender._id : msg.sender;
                        return (
                            <MessageBubble key={msg._id || msg.id} message={msg} isOwn={senderId === currentUser?._id} />
                        );
                    })
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="p-4 border-t border-dark-600 bg-dark-800">
                <form onSubmit={handleSend} className="flex items-center gap-2">
                    <button type="button" className="p-2 text-gray-400 hover:text-gray-200 hover:bg-dark-700 rounded-full">
                        <Paperclip className="w-5 h-5" />
                    </button>
                    <div className="flex-1 relative">
                        <input
                            type="text"
                            value={newMessage}
                            onChange={(e) => setNewMessage(e.target.value)}
                            placeholder="Type a message..."
                            className="w-full bg-dark-900 border border-dark-700 rounded-full pl-4 pr-10 py-2.5 text-sm text-gray-300 focus:outline-none focus:border-secondary transition-colors"
                        />
                        <button type="button" className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-200">
                            <Smile className="w-5 h-5" />
                        </button>
                    </div>
                    <button type="submit" disabled={!newMessage.trim()} className="p-2 bg-secondary text-white rounded-full hover:bg-secondary/80 disabled:opacity-50 disabled:cursor-not-allowed transform transition-transform active:scale-95">
                        <Send className="w-5 h-5" />
                    </button>
                </form>
            </div>
        </div>
    );
};

export default ChatWindow;

import Community from '../models/Community.model.js';
import User from '../models/User.model.js';
import { formatSuccess, formatError, getPaginationOptions, calculatePagination } from '../utils/formatResponse.js';
import { HTTP_STATUS } from '../utils/constants.js';
import { asyncHandler } from '../middleware/error.middleware.js';
import { getFileUrl } from '../middleware/upload.middleware.js';

/**
 * Create new community
 * POST /api/communities
 */
export const createCommunity = asyncHandler(async (req, res) => {
  const { name, displayName, description, college, rules } = req.body;
  const userId = req.userId;

  const community = new Community({
    name: name.toLowerCase().trim(),
    displayName,
    description,
    college,
    rules: rules || [],
    moderators: [userId],
    members: [userId],
    memberCount: 1,
    createdBy: userId
  });

  await community.save();

  // Add community to user's communities
  await User.findByIdAndUpdate(userId, {
    $push: { communities: community._id }
  });

  await community.populate('moderators', 'name avatar');

  res.status(HTTP_STATUS.CREATED).json(
    formatSuccess({
      message: 'Community created successfully',
      data: { community }
    })
  );
});

/**
 * Get all communities
 * GET /api/communities
 */
export const getCommunities = asyncHandler(async (req, res) => {
  const { page, limit, skip } = getPaginationOptions(req.query);
  const { college, search } = req.query;

  const filter = { isActive: true };

  if (college) {
    filter.college = { $regex: college, $options: 'i' };
  }

  if (search) {
    filter.$or = [
      { name: { $regex: search, $options: 'i' } },
      { displayName: { $regex: search, $options: 'i' } }
    ];
  }

  const total = await Community.countDocuments(filter);

  const communities = await Community.find(filter)
    .skip(skip)
    .limit(limit)
    .sort({ memberCount: -1 })
    .populate('moderators', 'name avatar');

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Communities retrieved successfully',
      data: { communities },
      pagination: calculatePagination(total, page, limit)
    })
  );
});

/**
 * Get community by ID
 * GET /api/communities/:id
 */
export const getCommunityById = asyncHandler(async (req, res) => {
  const { id } = req.params;

  let query;
  // Check if id is a valid ObjectId
  if (id.match(/^[0-9a-fA-F]{24}$/)) {
    query = Community.findById(id);
  } else {
    // Treat as name
    query = Community.findOne({ name: id.toLowerCase() });
  }

  const community = await query
    .populate('moderators', 'name avatar')
    .populate('createdBy', 'name avatar');

  if (!community) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Community not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  // Check if current user is a member
  const isMember = req.userId ? community.isMember(req.userId) : false;
  const isModerator = req.userId ? community.isModerator(req.userId) : false;

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Community retrieved successfully',
      data: {
        community: {
          ...community.toObject(),
          isMember,
          isModerator
        }
      }
    })
  );
});

/**
 * Update community
 * PUT /api/communities/:id
 */
export const updateCommunity = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const { description, rules, displayName } = req.body;

  const updateData = {};
  if (description) updateData.description = description;
  if (rules) updateData.rules = rules;
  if (displayName) updateData.displayName = displayName;

  const community = await Community.findByIdAndUpdate(
    id,
    updateData,
    { new: true, runValidators: true }
  );

  if (!community) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Community not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Community updated successfully',
      data: { community }
    })
  );
});

/**
 * Join community
 * POST /api/communities/:id/join
 */
export const joinCommunity = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const userId = req.userId;

  const community = await Community.findById(id);

  if (!community) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Community not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  if (community.isMember(userId)) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'You are already a member of this community',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Add user to community members
  community.addMember(userId);
  await community.save();

  // Add community to user's communities
  await User.findByIdAndUpdate(userId, {
    $push: { communities: community._id }
  });

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Joined community successfully',
      data: {
        isMember: true,
        memberCount: community.memberCount
      }
    })
  );
});

/**
 * Leave community
 * POST /api/communities/:id/leave
 */
export const leaveCommunity = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const userId = req.userId;

  const community = await Community.findById(id);

  if (!community) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Community not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  if (!community.isMember(userId)) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'You are not a member of this community',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Check if user is the only moderator
  if (community.isModerator(userId) && community.moderators.length === 1) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'You cannot leave as the only moderator. Transfer moderation first.',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Remove user from community members
  community.removeMember(userId);
  community.moderators = community.moderators.filter(
    mod => mod.toString() !== userId
  );
  await community.save();

  // Remove community from user's communities
  await User.findByIdAndUpdate(userId, {
    $pull: { communities: community._id }
  });

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Left community successfully',
      data: {
        isMember: false,
        memberCount: community.memberCount
      }
    })
  );
});

/**
 * Get community members
 * GET /api/communities/:id/members
 */
export const getMembers = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const { page, limit, skip } = getPaginationOptions(req.query);

  const community = await Community.findById(id).populate({
    path: 'members',
    select: 'name avatar college campusScore',
    options: { skip, limit }
  });

  if (!community) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Community not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  const total = community.memberCount;

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Members retrieved successfully',
      data: { members: community.members },
      pagination: calculatePagination(total, page, limit)
    })
  );
});

/**
 * Add moderator
 * POST /api/communities/:id/moderators
 */
export const addModerator = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const { userId: newModId } = req.body;

  const community = await Community.findById(id);

  if (!community) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Community not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  // Check if user is a member
  if (!community.isMember(newModId)) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'User must be a member to become a moderator',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Check if already moderator
  if (community.isModerator(newModId)) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'User is already a moderator',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  community.moderators.push(newModId);
  await community.save();

  await community.populate('moderators', 'name avatar');

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Moderator added successfully',
      data: { community }
    })
  );
});

/**
 * Remove moderator
 * DELETE /api/communities/:id/moderators/:userId
 */
export const removeModerator = asyncHandler(async (req, res) => {
  const { id, userId: modId } = req.params;

  const community = await Community.findById(id);

  if (!community) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Community not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  // Prevent removing the last moderator
  if (community.moderators.length <= 1) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'Cannot remove the last moderator',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  community.moderators = community.moderators.filter(
    mod => mod.toString() !== modId
  );
  await community.save();

  await community.populate('moderators', 'name avatar');

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Moderator removed successfully',
      data: { community }
    })
  );
});

/**
 * Upload community avatar
 * PUT /api/communities/:id/avatar
 */
export const uploadAvatar = asyncHandler(async (req, res) => {
  if (!req.file) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'No file uploaded',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  const { id } = req.params;
  const avatarUrl = getFileUrl(req.file.filename);

  const community = await Community.findByIdAndUpdate(
    id,
    { avatar: avatarUrl },
    { new: true }
  );

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Avatar uploaded successfully',
      data: { avatar: community.avatar }
    })
  );
});

