import Vote from '../models/Vote.model.js';
import Post from '../models/Post.model.js';
import Comment from '../models/Comment.model.js';
import { VOTE_VALUES, VOTE_TARGET_TYPES } from '../utils/constants.js';
import { updateCampusScore } from '../utils/generateCampusScore.js';

/**
 * Cast or update a vote
 * @param {string} userId - User ID
 * @param {string} targetId - Target ID (post or comment)
 * @param {string} targetType - Target type ('post' or 'comment')
 * @param {number} value - Vote value (1 or -1)
 * @returns {Object} Vote result
 */
export const vote = async (userId, targetId, targetType, value) => {
  // Validate vote value
  if (![VOTE_VALUES.UPVOTE, VOTE_VALUES.DOWNVOTE].includes(value)) {
    throw new Error('Invalid vote value. Must be 1 (upvote) or -1 (downvote)');
  }

  // Get target model
  const TargetModel = targetType === VOTE_TARGET_TYPES.POST ? Post : Comment;

  // Check if target exists
  const target = await TargetModel.findOne({ _id: targetId, isDeleted: false });
  if (!target) {
    throw new Error(`${targetType} not found`);
  }

  // Check if user is voting on their own content
  if (target.author.toString() === userId) {
    throw new Error('You cannot vote on your own content');
  }

  // Find existing vote
  let existingVote = await Vote.findByUserAndTarget(userId, targetId, targetType);

  let result = {
    action: null,
    previousValue: 0,
    newValue: value,
    targetScore: 0
  };

  if (existingVote) {
    // User is changing their vote
    if (existingVote.value === value) {
      // Same vote - remove it (toggle off)
      await Vote.deleteOne({ _id: existingVote._id });
      result.action = 'removed';
      result.previousValue = value;
      result.newValue = 0;

      // Update target vote counts
      if (value === VOTE_VALUES.UPVOTE) {
        target.upvotes -= 1;
      } else {
        target.downvotes -= 1;
      }
    } else {
      // Different vote - update it
      const oldValue = existingVote.value;
      existingVote.value = value;
      await existingVote.save();
      result.action = 'changed';
      result.previousValue = oldValue;
      result.newValue = value;

      // Update target vote counts
      if (oldValue === VOTE_VALUES.UPVOTE) {
        target.upvotes -= 1;
      } else {
        target.downvotes -= 1;
      }

      if (value === VOTE_VALUES.UPVOTE) {
        target.upvotes += 1;
      } else {
        target.downvotes += 1;
      }
    }
  } else {
    // New vote
    existingVote = new Vote({
      user: userId,
      targetId,
      targetType,
      value
    });
    await existingVote.save();
    result.action = 'created';
    result.previousValue = 0;
    result.newValue = value;

    // Update target vote counts
    if (value === VOTE_VALUES.UPVOTE) {
      target.upvotes += 1;
    } else {
      target.downvotes += 1;
    }
  }

  // Save target with updated vote counts
  await target.save();
  result.targetScore = target.score;

  // Update author's campus score if upvote
  if (value === VOTE_VALUES.UPVOTE && result.action !== 'removed') {
    await updateCampusScore(target.author);
  }

  return result;
};

/**
 * Remove a vote
 * @param {string} userId - User ID
 * @param {string} targetId - Target ID
 * @param {string} targetType - Target type
 * @returns {Object} Remove result
 */
export const removeVote = async (userId, targetId, targetType) => {
  const existingVote = await Vote.findByUserAndTarget(userId, targetId, targetType);

  if (!existingVote) {
    throw new Error('No vote found to remove');
  }

  // Get target model
  const TargetModel = targetType === VOTE_TARGET_TYPES.POST ? Post : Comment;
  const target = await TargetModel.findById(targetId);

  if (target) {
    // Update target vote counts
    if (existingVote.value === VOTE_VALUES.UPVOTE) {
      target.upvotes = Math.max(0, target.upvotes - 1);
    } else {
      target.downvotes = Math.max(0, target.downvotes - 1);
    }
    await target.save();
  }

  // Delete vote
  await Vote.deleteOne({ _id: existingVote._id });

  return {
    action: 'removed',
    previousValue: existingVote.value,
    newValue: 0,
    targetScore: target ? target.score : 0
  };
};

/**
 * Get user's vote on a target
 * @param {string} userId - User ID
 * @param {string} targetId - Target ID
 * @param {string} targetType - Target type
 * @returns {Object|null} Vote object or null
 */
export const getUserVote = async (userId, targetId, targetType) => {
  const vote = await Vote.findByUserAndTarget(userId, targetId, targetType);
  return vote ? { value: vote.value } : null;
};

/**
 * Get vote summary for a target
 * @param {string} targetId - Target ID
 * @param {string} targetType - Target type
 * @returns {Object} Vote summary
 */
export const getVoteSummary = async (targetId, targetType) => {
  return await Vote.getVoteSummary(targetId, targetType);
};

/**
 * Calculate and update target score
 * @param {string} targetId - Target ID
 * @param {string} targetType - Target type
 * @returns {number} Updated score
 */
export const calculateScore = async (targetId, targetType) => {
  const summary = await Vote.getVoteSummary(targetId, targetType);

  const TargetModel = targetType === VOTE_TARGET_TYPES.POST ? Post : Comment;
  await TargetModel.findByIdAndUpdate(targetId, {
    upvotes: summary.upvotes,
    downvotes: summary.downvotes,
    score: summary.total
  });

  return summary.total;
};

export default {
  vote,
  removeVote,
  getUserVote,
  getVoteSummary,
  calculateScore
};

import NotificationItem from '../components/notifications/NotificationItem';
import { useState, useEffect } from 'react';
import api from '../services/api';
import { useSocket } from '../context/SocketContext';
import { toast } from 'react-hot-toast';

const Notifications = () => {
    const [notifications, setNotifications] = useState([]);
    const [loading, setLoading] = useState(true);
    const { socket } = useSocket();

    const fetchNotifications = async () => {
        try {
            const response = await api.get('/notifications');
            setNotifications(response.data.data.notifications);
        } catch (error) {
            console.error('Failed to load notifications', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchNotifications();
    }, []);

    useEffect(() => {
        if (!socket) return;

        socket.on('new_notification', (data) => {
            setNotifications(prev => [data.notification, ...prev]);
            toast.success('New notification');
        });

        return () => {
            socket.off('new_notification');
        };
    }, [socket]);

    const markAllAsRead = async () => {
        try {
            await api.put('/notifications/read-all');
            setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
            toast.success('All marked as read');
        } catch (error) {
            toast.error('Failed to mark as read');
        }
    };

    const handleMarkAsRead = async (id) => {
        try {
            await api.put(`/notifications/${id}/read`);
            setNotifications(prev => prev.map(n => n.id === id || n._id === id ? ({ ...n, isRead: true }) : n));
        } catch (error) {
            console.error('Failed to mark read', error);
        }
    };

    return (
        <div className="max-w-3xl mx-auto">
            <div className="flex items-center justify-between mb-4 px-2">
                <h1 className="text-xl font-bold text-gray-200">Notifications</h1>
                <button
                    onClick={markAllAsRead}
                    className="text-xs text-secondary hover:underline font-bold"
                >
                    Mark all as read
                </button>
            </div>

            <div className="bg-dark-800 rounded-lg border border-dark-600 overflow-hidden">
                {loading ? (
                    <div className="p-4 text-center text-gray-500">Loading...</div>
                ) : notifications.length > 0 ? (
                    notifications.map(notification => (
                        <div key={notification._id || notification.id} onClick={() => handleMarkAsRead(notification._id || notification.id)}>
                            <NotificationItem notification={notification} />
                        </div>
                    ))
                ) : (
                    <div className="p-8 text-center text-gray-500">No notifications yet.</div>
                )}
            </div>
        </div>
    );
};

export default Notifications;

import Post from '../models/Post.model.js';
import Community from '../models/Community.model.js';
import Vote from '../models/Vote.model.js';
import { SORT_OPTIONS, VOTE_TARGET_TYPES } from '../utils/constants.js';
import { getPaginationOptions, calculatePagination } from '../utils/formatResponse.js';

/**
 * Helper to populate user votes for a list of posts
 * @param {Array} posts - List of posts
 * @param {string} userId - Current user ID
 * @returns {Promise<Array>} Posts with userVote populated
 */
const populateUserVotes = async (posts, userId) => {
  if (!userId || !posts.length) {
    return posts.map(post => ({
      ...post.toObject(),
      userVote: 0
    }));
  }

  const postIds = posts.map(p => p._id);

  const votes = await Vote.find({
    user: userId,
    targetId: { $in: postIds },
    targetType: VOTE_TARGET_TYPES.POST
  });

  const voteMap = votes.reduce((acc, vote) => {
    acc[vote.targetId.toString()] = vote.value;
    return acc;
  }, {});

  return posts.map(post => ({
    ...post.toObject(),
    userVote: voteMap[post._id.toString()] || 0
  }));
};

/**
 * Create a new post
 * @param {Object} postData - Post data
 * @param {string} userId - Author ID
 * @returns {Object} Created post
 */
export const createPost = async (postData, userId) => {
  const { communityId, type, title, content, images, poll, event, flair } = postData;

  // Verify community exists and user is a member only if communityId is provided
  if (communityId) {
    const community = await Community.findById(communityId);
    if (!community) {
      throw new Error('Community not found');
    }

    if (!community.isMember(userId)) {
      throw new Error('You must be a member of this community to post');
    }
  }

  const post = new Post({
    author: userId,
    community: communityId || undefined,
    type,
    title,
    content,
    images: images || [],
    poll: type === 'poll' ? poll : undefined,
    event: type === 'event' ? event : undefined,
    flair
  });

  await post.save();
  await post.populate('author', 'name avatar');
  if (communityId) {
    await post.populate('community', 'name displayName');
  }

  return post;
};

/**
 * Get post by ID
 * @param {string} postId - Post ID
 * @returns {Object} Post
 */
export const getPostById = async (postId) => {
  const post = await Post.findOne({ _id: postId, isDeleted: false })
    .populate('author', 'name avatar')
    .populate('community', 'name displayName');

  if (!post) {
    throw new Error('Post not found');
  }

  return post;
};

/**
 * Get feed with sorting and pagination
 * @param {Object} query - Query parameters
 * @param {string} userId - User ID (optional, for personalized feed)
 * @returns {Object} Posts and pagination
 */
export const getFeed = async (query, userId = null) => {
  const { page, limit, skip } = getPaginationOptions(query);
  const { sort = SORT_OPTIONS.HOT, communityId, type } = query;

  // Build filter
  const filter = { isDeleted: false };

  if (communityId) {
    filter.community = communityId;
  }

  if (type) {
    filter.type = type;
  }

  // Determine sort order
  let sortOption = {};
  switch (sort) {
    case SORT_OPTIONS.HOT:
      sortOption = { hotScore: -1, createdAt: -1 };
      break;
    case SORT_OPTIONS.NEW:
      sortOption = { createdAt: -1 };
      break;
    case SORT_OPTIONS.TOP:
      sortOption = { score: -1, createdAt: -1 };
      break;
    default:
      sortOption = { hotScore: -1, createdAt: -1 };
  }

  // Get total count
  const total = await Post.countDocuments(filter);

  // Get posts
  const posts = await Post.find(filter)
    .sort(sortOption)
    .skip(skip)
    .limit(limit)
    .populate('author', 'name avatar')
    .populate('community', 'name displayName');

  const postsWithVotes = await populateUserVotes(posts, userId);

  return {
    posts: postsWithVotes,
    pagination: calculatePagination(total, page, limit)
  };
};

/**
 * Get posts by community
 * @param {string} communityId - Community ID
 * @param {Object} query - Query parameters
 * @param {string} userId - User ID (optional)
 * @returns {Object} Posts and pagination
 */
export const getCommunityPosts = async (communityId, query, userId = null) => {
  const { page, limit, skip } = getPaginationOptions(query);
  const { sort = SORT_OPTIONS.HOT } = query;

  const filter = { community: communityId, isDeleted: false };

  let sortOption = {};
  switch (sort) {
    case SORT_OPTIONS.HOT:
      sortOption = { hotScore: -1, createdAt: -1 };
      break;
    case SORT_OPTIONS.NEW:
      sortOption = { createdAt: -1 };
      break;
    case SORT_OPTIONS.TOP:
      sortOption = { score: -1, createdAt: -1 };
      break;
    default:
      sortOption = { hotScore: -1, createdAt: -1 };
  }

  const total = await Post.countDocuments(filter);

  const posts = await Post.find(filter)
    .sort(sortOption)
    .skip(skip)
    .limit(limit)
    .populate('author', 'name avatar')
    .populate('community', 'name displayName');

  const postsWithVotes = await populateUserVotes(posts, userId);

  return {
    posts: postsWithVotes,
    pagination: calculatePagination(total, page, limit)
  };
};

/**
 * Get posts by user
 * @param {string} targetUserId - Target User ID
 * @param {Object} query - Query parameters
 * @param {string} currentUserId - Current User ID (viewing)
 * @returns {Object} Posts and pagination
 */
export const getUserPosts = async (targetUserId, query, currentUserId = null) => {
  const { page, limit, skip } = getPaginationOptions(query);

  const filter = { author: targetUserId, isDeleted: false };

  const total = await Post.countDocuments(filter);

  const posts = await Post.find(filter)
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)
    .populate('community', 'name displayName');

  const postsWithVotes = await populateUserVotes(posts, currentUserId);

  return {
    posts: postsWithVotes,
    pagination: calculatePagination(total, page, limit)
  };
};

/**
 * Update post
 * @param {string} postId - Post ID
 * @param {Object} updateData - Update data
 * @param {string} userId - User ID
 * @returns {Object} Updated post
 */
export const updatePost = async (postId, updateData, userId) => {
  const post = await Post.findOne({ _id: postId, isDeleted: false });

  if (!post) {
    throw new Error('Post not found');
  }

  // Check ownership
  if (post.author.toString() !== userId) {
    throw new Error('You can only edit your own posts');
  }

  // Check if post is locked
  if (post.isLocked) {
    throw new Error('This post is locked and cannot be edited');
  }

  const allowedUpdates = ['title', 'content', 'images', 'flair', 'event'];

  allowedUpdates.forEach(field => {
    if (updateData[field] !== undefined) {
      post[field] = updateData[field];
    }
  });

  await post.save();
  await post.populate('author', 'name avatar');
  await post.populate('community', 'name displayName');

  return post;
};

/**
 * Soft delete post
 * @param {string} postId - Post ID
 * @param {string} userId - User ID
 * @param {boolean} isAdmin - Whether user is admin
 */
export const softDeletePost = async (postId, userId, isAdmin = false) => {
  const post = await Post.findOne({ _id: postId, isDeleted: false });

  if (!post) {
    throw new Error('Post not found');
  }

  // Check ownership or admin
  if (!isAdmin && post.author.toString() !== userId) {
    throw new Error('You can only delete your own posts');
  }

  post.softDelete(isAdmin ? null : userId);
  await post.save();

  return true;
};

/**
 * Increment comment count
 * @param {string} postId - Post ID
 */
export const incrementCommentCount = async (postId) => {
  await Post.findByIdAndUpdate(postId, { $inc: { commentCount: 1 } });
};

/**
 * Decrement comment count
 * @param {string} postId - Post ID
 */
export const decrementCommentCount = async (postId) => {
  await Post.findByIdAndUpdate(postId, { $inc: { commentCount: -1 } });
};

export default {
  createPost,
  getPostById,
  getFeed,
  getCommunityPosts,
  getUserPosts,
  updatePost,
  softDeletePost,
  incrementCommentCount,
  decrementCommentCount
};

