import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import User from '../models/User.model.js';
import env from '../config/env.js';

/**
 * Generate JWT tokens
 * @param {Object} user - User object
 * @returns {Object} Access and refresh tokens
 */
export const generateTokens = (user) => {
  const payload = {
    userId: user._id.toString(),
    email: user.email,
    role: user.role
  };

  const accessToken = jwt.sign(payload, env.JWT_ACCESS_SECRET, {
    expiresIn: env.JWT_ACCESS_EXPIRY
  });

  const refreshToken = jwt.sign(
    { userId: user._id.toString() },
    env.JWT_REFRESH_SECRET,
    { expiresIn: env.JWT_REFRESH_EXPIRY }
  );

  return { accessToken, refreshToken };
};

/**
 * Register a new user
 * @param {Object} userData - User registration data
 * @returns {Object} User and tokens
 */
export const register = async (userData) => {
  const { name, email, password, college, course, year, graduationYear, bio, skills, role } = userData;

  // Check if user already exists
  const existingUser = await User.findOne({ email });
  if (existingUser) {
    throw new Error('User with this email already exists');
  }

  // Create new user
  const user = new User({
    name,
    email,
    password,
    college,
    course,
    year,
    graduationYear,
    bio,
    skills: skills || [],
    role: role || 'student'
  });

  await user.save();

  // Generate tokens
  const { accessToken, refreshToken } = generateTokens(user);

  // Save refresh token
  user.refreshToken = refreshToken;
  await user.save();

  return {
    user: user.toPublicProfile(),
    accessToken,
    refreshToken
  };
};

/**
 * Login user
 * @param {string} email - User email
 * @param {string} password - User password
 * @returns {Object} User and tokens
 */
export const login = async (email, password) => {
  // Find user with password
  const user = await User.findOne({ email })
    .select('+password')
    .populate('communities', 'name displayName avatar');

  if (!user) {
    throw new Error('Invalid email or password');
  }

  // Check if user is banned
  if (user.isBanned) {
    throw new Error('Your account has been banned');
  }

  // Verify password
  const isPasswordValid = await user.comparePassword(password);

  if (!isPasswordValid) {
    throw new Error('Invalid email or password');
  }

  // Generate tokens
  const { accessToken, refreshToken } = generateTokens(user);

  // Save refresh token
  user.refreshToken = refreshToken;
  await user.save();

  return {
    user: user.toPublicProfile(),
    accessToken,
    refreshToken
  };
};

/**
 * Refresh access token
 * @param {string} token - Refresh token
 * @returns {Object} New tokens
 */
export const refreshToken = async (token) => {
  try {
    // Verify refresh token
    const decoded = jwt.verify(token, env.JWT_REFRESH_SECRET);

    // Find user
    const user = await User.findById(decoded.userId)
      .select('+refreshToken')
      .populate('communities', 'name displayName avatar');

    if (!user) {
      throw new Error('User not found');
    }

    // Check if refresh token matches
    if (user.refreshToken !== token) {
      throw new Error('Invalid refresh token');
    }

    // Check if user is banned
    if (user.isBanned) {
      throw new Error('Your account has been banned');
    }

    // Generate new tokens
    const tokens = generateTokens(user);

    // Save new refresh token
    user.refreshToken = tokens.refreshToken;
    await user.save();

    return {
      user: user.toPublicProfile(),
      ...tokens
    };
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      throw new Error('Refresh token expired');
    }
    throw error;
  }
};

/**
 * Logout user
 * @param {string} userId - User ID
 */
export const logout = async (userId) => {
  await User.findByIdAndUpdate(userId, { refreshToken: null });
};

/**
 * Logout from all devices
 * @param {string} userId - User ID
 */
export const logoutAll = async (userId) => {
  await User.findByIdAndUpdate(userId, { refreshToken: null });
};

/**
 * Change password
 * @param {string} userId - User ID
 * @param {string} currentPassword - Current password
 * @param {string} newPassword - New password
 */
export const changePassword = async (userId, currentPassword, newPassword) => {
  const user = await User.findById(userId).select('+password');

  if (!user) {
    throw new Error('User not found');
  }

  // Verify current password
  const isPasswordValid = await user.comparePassword(currentPassword);

  if (!isPasswordValid) {
    throw new Error('Current password is incorrect');
  }

  // Update password
  user.password = newPassword;
  await user.save();

  return true;
};

/**
 * Login as guest
 * @returns {Object} User and tokens
 */
export const guestLogin = async () => {
  const GUEST_EMAIL = 'guest@collegeconnect.edu';

  let user = await User.findOne({ email: GUEST_EMAIL });

  if (!user) {
    // Create guest user if not exists
    user = new User({
      name: 'Guest Student',
      email: GUEST_EMAIL,
      password: 'GuestPassword123!', // Strong password to pass validation
      college: 'Guest University',
      course: 'Visitor',
      year: 1,
      bio: 'Just visiting CollegeConnect',
      skills: ['Exploration'],
      role: 'student'
    });
    await user.save();
  } else if (user.isBanned) {
    throw new Error('Guest account is banned');
  }

  // Generate tokens
  const { accessToken, refreshToken } = generateTokens(user);

  // Save refresh token
  user.refreshToken = refreshToken;
  await user.save();

  return {
    user: user.toPublicProfile(),
    accessToken,
    refreshToken
  };
};

export default {
  register,
  login,
  guestLogin,
  refreshToken,
  logout,
  logoutAll,
  changePassword,
  generateTokens
};

import { useParams } from 'react-router-dom';
import { useState, useEffect } from 'react';
import ProfileHeader from '../components/profile/ProfileHeader';
import PostCard from '../components/post/PostCard';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';

const ProfilePage = () => {
    const { userId } = useParams();
    const { user: currentUser } = useAuth();
    const [profileUser, setProfileUser] = useState(null);
    const [posts, setPosts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        const fetchProfileData = async () => {
            setLoading(true);
            try {
                const userRes = await api.get(`/users/${userId}`);
                const userData = userRes.data.data.user;
                setProfileUser(userData);

                const postsRes = await api.get(`/posts/user/${userData._id}`);
                setPosts(postsRes.data.data.posts);
            } catch (err) {
                console.error("Failed to load profile:", err);
                setError("User not found or failed to load");
            } finally {
                setLoading(false);
            }
        };

        if (userId) {
            fetchProfileData();
        }
    }, [userId]);

    if (loading) return <div className="text-center py-10">Loading profile...</div>;
    if (error) return <div className="text-center py-10 text-red-500">{error}</div>;
    if (!profileUser) return null;

    return (
        <div>
            <ProfileHeader
                user={profileUser}
                isOwnProfile={currentUser?._id === profileUser._id}
                onUpdate={setProfileUser}
            />

            <div className="space-y-4">
                <h3 className="text-lg font-bold text-gray-200">Posts</h3>
                {posts.length > 0 ? (
                    posts.map(post => <PostCard key={post._id} post={post} />)
                ) : (
                    <div className="text-center py-10 text-gray-500 bg-dark-800 rounded-lg border border-dark-600">
                        This user hasn't posted anything yet.
                    </div>
                )}
            </div>
        </div>
    );
};

export default ProfilePage;

import Message from '../models/Message.model.js';
import User from '../models/User.model.js';
import * as notificationService from '../services/notification.service.js';
import { formatSuccess, formatError, getPaginationOptions, calculatePagination } from '../utils/formatResponse.js';
import { HTTP_STATUS } from '../utils/constants.js';
import { asyncHandler } from '../middleware/error.middleware.js';
import { isUserOnline, getIO } from '../config/socket.js';

/**
 * Get user's conversations
 * GET /api/chat/conversations
 */
export const getConversations = asyncHandler(async (req, res) => {
  const userId = req.userId;

  const conversations = await Message.getConversations(userId);

  // Populate user details for each conversation
  const populatedConversations = await Promise.all(
    conversations.map(async (conv) => {
      const otherUser = await User.findById(conv._id).select('name avatar');
      return {
        user: otherUser,
        lastMessage: conv.lastMessage,
        unreadCount: conv.unreadCount
      };
    })
  );

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Conversations retrieved successfully',
      data: { conversations: populatedConversations }
    })
  );
});

/**
 * Get conversation messages
 * GET /api/chat/messages/:userId
 */
export const getMessages = asyncHandler(async (req, res) => {
  const { userId: otherUserId } = req.params;
  const currentUserId = req.userId;
  const { page, limit, skip } = getPaginationOptions(req.query);

  // Check if other user exists
  const otherUser = await User.findById(otherUserId);
  if (!otherUser) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'User not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  // Get messages
  const messages = await Message.getConversation(
    currentUserId,
    otherUserId,
    { limit, skip }
  );

  // Count total for pagination
  const total = await Message.countDocuments({
    $or: [
      { sender: currentUserId, receiver: otherUserId },
      { sender: otherUserId, receiver: currentUserId }
    ],
    isDeleted: false
  });

  // Mark unread messages as read
  await Message.updateMany(
    {
      sender: otherUserId,
      receiver: currentUserId,
      isRead: false
    },
    { isRead: true, readAt: new Date() }
  );

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Messages retrieved successfully',
      data: { messages },
      pagination: calculatePagination(total, page, limit)
    })
  );
});

/**
 * Send message (REST API fallback)
 * POST /api/chat/messages/:userId
 */
export const sendMessage = asyncHandler(async (req, res) => {
  const { userId: receiverId } = req.params;
  const senderId = req.userId;
  const { content } = req.body;

  // Check if receiver exists
  const receiver = await User.findById(receiverId);
  if (!receiver) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'User not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  // Cannot message yourself
  if (senderId === receiverId) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'Cannot send message to yourself',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Create message
  const message = new Message({
    sender: senderId,
    receiver: receiverId,
    content
  });

  await message.save();

  await message.populate('sender', 'name avatar');
  await message.populate('receiver', 'name avatar');

  // Emit to receiver if online
  const io = getIO();
  io.to(`user:${receiverId}`).emit('new_message', {
    message: {
      id: message._id,
      sender: message.sender,
      content: message.content,
      createdAt: message.createdAt
    }
  });

  // Create notification
  await notificationService.createMessageNotification(
    receiverId,
    senderId,
    message._id
  );

  res.status(HTTP_STATUS.CREATED).json(
    formatSuccess({
      message: 'Message sent successfully',
      data: { message }
    })
  );
});

/**
 * Delete message
 * DELETE /api/chat/messages/:id
 */
export const deleteMessage = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const userId = req.userId;

  const message = await Message.findById(id);

  if (!message) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Message not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  // Can only delete own messages
  if (message.sender.toString() !== userId) {
    return res.status(HTTP_STATUS.FORBIDDEN).json(
      formatError({
        message: 'Can only delete your own messages',
        statusCode: HTTP_STATUS.FORBIDDEN
      })
    );
  }

  message.softDelete(userId);
  await message.save();

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Message deleted successfully',
      data: null
    })
  );
});

/**
 * Mark message as read
 * PUT /api/chat/messages/:id/read
 */
export const markAsRead = asyncHandler(async (req, res) => {
  const { id } = req.params;
  const userId = req.userId;

  const message = await Message.findOne({
    _id: id,
    receiver: userId
  });

  if (!message) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Message not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  message.markAsRead();
  await message.save();

  // Notify sender that message was read
  const io = getIO();
  io.to(`user:${message.sender}`).emit('message_read', {
    messageId: message._id,
    readAt: message.readAt
  });

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Message marked as read',
      data: { message }
    })
  );
});

/**
 * Get unread message count
 * GET /api/chat/unread-count
 */
export const getUnreadCount = asyncHandler(async (req, res) => {
  const userId = req.userId;

  const count = await Message.countDocuments({
    receiver: userId,
    isRead: false,
    isDeleted: false
  });

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Unread count retrieved successfully',
      data: { count }
    })
  );
});

export default {
  getConversations,
  getMessages,
  sendMessage,
  deleteMessage,
  markAsRead,
  getUnreadCount
};

import { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate, Link } from 'react-router-dom';

const Login = () => {
    const { login } = useAuth();
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        email: '',
        password: ''
    });
    const [error, setError] = useState('');

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);
        try {
            await login(formData.email, formData.password);
            navigate('/');
        } catch (err) {
            setError(err || 'Failed to login');
        } finally {
            setLoading(false);
        }
