import Notification from '../models/Notification.model.js';

/**
 * Handle notification socket events
 * @param {Socket} socket - Socket.io socket instance
 * @param {IO} io - Socket.io server instance
 */
export const handleNotificationSocket = (socket, io) => {
  // Join user's personal notification room
  socket.on('join_notifications', () => {
    socket.join(`user:${socket.userId}`);
    console.log(`User ${socket.userId} joined notification room`);
  });

  // Leave notification room
  socket.on('leave_notifications', () => {
    socket.leave(`user:${socket.userId}`);
    console.log(`User ${socket.userId} left notification room`);
  });

  // Get notifications
  socket.on('get_notifications', async (data, callback) => {
    try {
      const { page = 1, limit = 20, unreadOnly = false } = data;
      const skip = (page - 1) * limit;

      const filter = { recipient: socket.userId, isDeleted: false };

      if (unreadOnly) {
        filter.isRead = false;
      }

      const notifications = await Notification.find(filter)
        .sort({ createdAt: -1 })
        .skip(skip)
        .limit(limit)
        .populate('sender', 'name avatar');

      const total = await Notification.countDocuments(filter);
      const unreadCount = await Notification.getUnreadCount(socket.userId);

      if (callback) {
        callback({
          success: true,
          notifications,
          pagination: {
            page,
            limit,
            total,
            totalPages: Math.ceil(total / limit)
          },
          unreadCount
        });
      }
    } catch (error) {
      console.error('Error getting notifications:', error);
      if (callback) callback({ success: false, error: error.message });
    }
  });

  // Mark notification as read
  socket.on('mark_notification_read', async (data, callback) => {
    try {
      const { notificationId } = data;

      const notification = await Notification.findOne({
        _id: notificationId,
        recipient: socket.userId
      });

      if (!notification) {
        if (callback) callback({ success: false, error: 'Notification not found' });
        return;
      }

      notification.markAsRead();
      await notification.save();

      // Get updated unread count
      const unreadCount = await Notification.getUnreadCount(socket.userId);

      if (callback) callback({ success: true, unreadCount });
    } catch (error) {
      console.error('Error marking notification as read:', error);
      if (callback) callback({ success: false, error: error.message });
    }
  });

  // Mark all notifications as read
  socket.on('mark_all_notifications_read', async (data, callback) => {
    try {
      await Notification.markAllAsRead(socket.userId);

      if (callback) callback({ success: true, unreadCount: 0 });
    } catch (error) {
      console.error('Error marking all notifications as read:', error);
      if (callback) callback({ success: false, error: error.message });
    }
  });

  // Delete notification
  socket.on('delete_notification', async (data, callback) => {
    try {
      const { notificationId } = data;

      const notification = await Notification.findOne({
        _id: notificationId,
        recipient: socket.userId
      });

      if (!notification) {
        if (callback) callback({ success: false, error: 'Notification not found' });
        return;
      }

      notification.isDeleted = true;
      await notification.save();

      // Get updated unread count
      const unreadCount = await Notification.getUnreadCount(socket.userId);

      if (callback) callback({ success: true, unreadCount });
    } catch (error) {
      console.error('Error deleting notification:', error);
      if (callback) callback({ success: false, error: error.message });
    }
  });

  // Get unread count
  socket.on('get_unread_count', async (data, callback) => {
    try {
      const unreadCount = await Notification.getUnreadCount(socket.userId);

      if (callback) callback({ success: true, unreadCount });
    } catch (error) {
      console.error('Error getting unread count:', error);
      if (callback) callback({ success: false, error: error.message });
    }
  });

  // Acknowledge notification received
  socket.on('notification_received', (data) => {
    const { notificationId } = data;
    console.log(`Notification ${notificationId} received by user ${socket.userId}`);
  });
};

/**
 * Emit notification to specific user
 * @param {IO} io - Socket.io server instance
 * @param {string} userId - User ID
 * @param {Object} notification - Notification data
 */
export const emitNotification = (io, userId, notification) => {
  io.to(`user:${userId}`).emit('new_notification', {
    notification: {
      id: notification._id,
      type: notification.type,
      title: notification.title,
      message: notification.message,
      targetId: notification.targetId,
      targetType: notification.targetType,
      isRead: notification.isRead,
      createdAt: notification.createdAt,
      sender: notification.sender
    }
  });
};

export default { handleNotificationSocket, emitNotification };

import { body, validationResult } from 'express-validator';
import { POST_TYPES, VALIDATION } from '../utils/constants.js';
import { formatError } from '../utils/formatResponse.js';
import { HTTP_STATUS } from '../utils/constants.js';

/**
 * Handle validation errors
 */
const handleValidationErrors = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'Validation failed',
        errors: errors.array().map(err => ({
          field: err.path,
          message: err.msg
        })),
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }
  next();
};

/**
 * Validate post creation
 */
export const validatePost = [
  body('communityId')
    .optional({ checkFalsy: true })
    .isMongoId()
    .withMessage('Invalid community ID'),

  body('type')
    .notEmpty()
    .withMessage('Post type is required')
    .isIn(Object.values(POST_TYPES))
    .withMessage(`Type must be one of: ${Object.values(POST_TYPES).join(', ')}`),

  body('title')
    .trim()
    .notEmpty()
    .withMessage('Title is required')
    .isLength({ max: VALIDATION.MAX_TITLE_LENGTH })
    .withMessage(`Title cannot exceed ${VALIDATION.MAX_TITLE_LENGTH} characters`),

  body('content')
    .optional()
    .trim()
    .isLength({ max: 10000 })
    .withMessage('Content cannot exceed 10000 characters'),

  body('flair')
    .optional()
    .trim()
    .isLength({ max: 50 })
    .withMessage('Flair cannot exceed 50 characters'),

  // Validate poll options if type is poll
  body('poll').custom((value, { req }) => {
    if (req.body.type === 'poll') {
      if (!value || !value.options || !Array.isArray(value.options)) {
        throw new Error('Poll options are required for poll posts');
      }
      if (value.options.length < VALIDATION.MIN_POLL_OPTIONS) {
        throw new Error(`Poll must have at least ${VALIDATION.MIN_POLL_OPTIONS} options`);
      }
      if (value.options.length > VALIDATION.MAX_POLL_OPTIONS) {
        throw new Error(`Poll cannot have more than ${VALIDATION.MAX_POLL_OPTIONS} options`);
      }

      // Validate each option
      value.options.forEach((option, index) => {
        if (!option.text || option.text.trim().length === 0) {
          throw new Error(`Option ${index + 1} text is required`);
        }
        if (option.text.length > 200) {
          throw new Error(`Option ${index + 1} text cannot exceed 200 characters`);
        }
      });
    }
    return true;
  }),

  // Validate event details if type is event
  body('event').custom((value, { req }) => {
    if (req.body.type === 'event') {
      if (!value) {
        throw new Error('Event details are required for event posts');
      }
      if (!value.date) {
        throw new Error('Event date is required');
      }
      if (isNaN(Date.parse(value.date))) {
        throw new Error('Invalid event date');
      }
      if (value.location && value.location.length > 200) {
        throw new Error('Event location cannot exceed 200 characters');
      }
    }
    return true;
  }),

  handleValidationErrors
];

/**
 * Validate vote
 */
export const validateVote = [
  body('value')
    .notEmpty()
    .withMessage('Vote value is required')
    .isIn([-1, 1])
    .withMessage('Vote value must be 1 (upvote) or -1 (downvote)'),

  handleValidationErrors
];

/**
 * Validate poll vote
 */
export const validatePollVote = [
  body('optionIndex')
    .notEmpty()
    .withMessage('Option index is required')
    .isInt({ min: 0 })
    .withMessage('Option index must be a non-negative integer'),

  handleValidationErrors
];

export default {
  validatePost,
  validateVote,
  validatePollVote
};

import { usePosts } from '../context/PostContext';
import PostCard from '../components/post/PostCard';
import CreatePostBox from '../components/post/CreatePostBox';
import PostSkeleton from '../components/post/PostSkeleton';
import clsx from 'clsx';
import { useEffect, useRef, useCallback } from 'react';

const Home = () => {
    const { posts, loading, setSortBy, sortBy, hasMore, loadMore } = usePosts();
    const observer = useRef();

    const lastPostRef = useCallback(node => {
        if (loading) return;
        if (observer.current) observer.current.disconnect();

        observer.current = new IntersectionObserver(entries => {
            if (entries[0].isIntersecting && hasMore) {
                loadMore();
            }
        });

        if (node) observer.current.observe(node);
    }, [loading, hasMore, loadMore]);

    return (
        <div className="space-y-6 pb-20">
            <CreatePostBox />

            {/* Sort Tabs - Modern Glass Version */}
            <div className="flex items-center p-1 bg-dark-800/50 backdrop-blur-sm border border-white/5 rounded-2xl w-fit ml-2">
                {['hot', 'new', 'top'].map((type) => (
                    <button
                        key={type}
                        onClick={() => setSortBy(type)}
                        className={clsx(
                            "px-5 py-1.5 rounded-xl text-xs font-extrabold capitalize transition-all duration-300",
                            sortBy === type 
                                ? "bg-white/10 text-white shadow-premium" 
                                : "text-gray-500 hover:text-gray-300 hover:bg-white/5"
                        )}
                    >
                        {type}
                    </button>
                ))}
            </div>

            <div className="space-y-4">
                {posts.length > 0 ? (
                    posts.map((post, index) => {
                        if (posts.length === index + 1) {
                            return (
                                <div ref={lastPostRef} key={post._id}>
                                    <PostCard post={post} />
                                </div>
                            );
                        } else {
                            return <PostCard key={post._id} post={post} />;
