import { formatError } from '../utils/formatResponse.js';
import { HTTP_STATUS, USER_ROLES } from '../utils/constants.js';

/**
 * Check if user has required role(s)
 * @param  {...string} allowedRoles - Roles that are allowed to access
 */
export const requireRole = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(HTTP_STATUS.UNAUTHORIZED).json(
        formatError({
          message: 'Authentication required.',
          statusCode: HTTP_STATUS.UNAUTHORIZED
        })
      );
    }

    if (!allowedRoles.includes(req.user.role)) {
      return res.status(HTTP_STATUS.FORBIDDEN).json(
        formatError({
          message: 'You do not have permission to perform this action.',
          statusCode: HTTP_STATUS.FORBIDDEN
        })
      );
    }

    next();
  };
};

/**
 * Require admin role
 */
export const requireAdmin = requireRole(USER_ROLES.ADMIN);

/**
 * Require campus lead or admin role
 */
export const requireCampusLeadOrAdmin = requireRole(USER_ROLES.CAMPUS_LEAD, USER_ROLES.ADMIN);

/**
 * Check if user owns the resource or is admin
 * @param {Function} getResourceOwnerId - Function to extract owner ID from req
 */
export const requireOwnershipOrAdmin = (getResourceOwnerId) => {
  return async (req, res, next) => {
    try {
      if (!req.user) {
        return res.status(HTTP_STATUS.UNAUTHORIZED).json(
          formatError({
            message: 'Authentication required.',
            statusCode: HTTP_STATUS.UNAUTHORIZED
          })
        );
      }

      // Admin can access anything
      if (req.user.role === USER_ROLES.ADMIN) {
        return next();
      }

      const ownerId = await getResourceOwnerId(req);

      if (req.userId !== ownerId.toString()) {
        return res.status(HTTP_STATUS.FORBIDDEN).json(
          formatError({
            message: 'You do not have permission to access this resource.',
            statusCode: HTTP_STATUS.FORBIDDEN
          })
        );
      }

      next();
    } catch (error) {
      return res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json(
        formatError({
          message: 'Error checking resource ownership.',
          statusCode: HTTP_STATUS.INTERNAL_SERVER_ERROR
        })
      );
    }
  };
};

/**
 * Check if user is community moderator
 * Requires communityId to be in req.params
 */
export const requireCommunityModerator = async (req, res, next) => {
  try {
    if (!req.user) {
      return res.status(HTTP_STATUS.UNAUTHORIZED).json(
        formatError({
          message: 'Authentication required.',
          statusCode: HTTP_STATUS.UNAUTHORIZED
        })
      );
    }

    // Admin can moderate any community
    if (req.user.role === USER_ROLES.ADMIN) {
      return next();
    }

    const Community = (await import('../models/Community.model.js')).default;
    const community = await Community.findById(req.params.id);

    if (!community) {
      return res.status(HTTP_STATUS.NOT_FOUND).json(
        formatError({
          message: 'Community not found.',
          statusCode: HTTP_STATUS.NOT_FOUND
        })
      );
    }

    if (!community.isModerator(req.userId)) {
      return res.status(HTTP_STATUS.FORBIDDEN).json(
        formatError({
          message: 'You must be a community moderator to perform this action.',
          statusCode: HTTP_STATUS.FORBIDDEN
        })
      );
    }

    req.community = community;
    next();
  } catch (error) {
    return res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json(
      formatError({
        message: 'Error checking moderator status.',
        statusCode: HTTP_STATUS.INTERNAL_SERVER_ERROR
      })
    );
  }
};

export default {
  requireRole,
  requireAdmin,
  requireCampusLeadOrAdmin,
  requireOwnershipOrAdmin,
  requireCommunityModerator
};

import Report from '../models/Report.model.js';
import Post from '../models/Post.model.js';
import Comment from '../models/Comment.model.js';
import User from '../models/User.model.js';
import { formatSuccess, formatError } from '../utils/formatResponse.js';
import { HTTP_STATUS, REPORT_TARGET_TYPES } from '../utils/constants.js';
import { asyncHandler } from '../middleware/error.middleware.js';

/**
 * Create report
 * POST /api/reports
 */
export const createReport = asyncHandler(async (req, res) => {
  const { targetId, targetType, reason, description } = req.body;
  const reporterId = req.userId;

  // Validate target type
  if (!Object.values(REPORT_TARGET_TYPES).includes(targetType)) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'Invalid target type',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Check if target exists
  let target;
  switch (targetType) {
    case REPORT_TARGET_TYPES.POST:
      target = await Post.findById(targetId);
      break;
    case REPORT_TARGET_TYPES.COMMENT:
      target = await Comment.findById(targetId);
      break;
    case REPORT_TARGET_TYPES.USER:
      target = await User.findById(targetId);
      break;
  }

  if (!target) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({
        message: 'Report target not found',
        statusCode: HTTP_STATUS.NOT_FOUND
      })
    );
  }

  // Check if user already reported this target
  const alreadyReported = await Report.hasReported(reporterId, targetId, targetType);
  if (alreadyReported) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'You have already reported this content',
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }

  // Create report
  const report = new Report({
    reporter: reporterId,
    targetId,
    targetType,
    reason,
    description
  });

  await report.save();

  res.status(HTTP_STATUS.CREATED).json(
    formatSuccess({
      message: 'Report submitted successfully',
      data: { report }
    })
  );
});

/**
 * Get user's reports
 * GET /api/reports/my-reports
 */
export const getMyReports = asyncHandler(async (req, res) => {
  const reporterId = req.userId;

  const reports = await Report.find({ reporter: reporterId })
    .sort({ createdAt: -1 })
    .populate('resolvedBy', 'name');

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Reports retrieved successfully',
      data: { reports }
    })
  );
});

export default {
  createReport,
  getMyReports
};

import User from '../models/User.model.js';
import Community from '../models/Community.model.js';
import Resource from '../models/Resource.model.js';
import { formatSuccess } from '../utils/formatResponse.js';
import { HTTP_STATUS } from '../utils/constants.js';
import { asyncHandler } from '../middleware/error.middleware.js';

/**
 * Global Search
 * GET /api/search
 */
export const globalSearch = asyncHandler(async (req, res) => {
  const { q } = req.query;
  const limit = 5;

  if (!q) {
    return res.status(HTTP_STATUS.OK).json(
      formatSuccess({
        message: 'Empty query',
        data: { users: [], communities: [], resources: [] }
      })
    );
  }

  // Escape special regex characters to prevent ReDoS/Injection
  const escapedQ = q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const query = { $regex: escapedQ, $options: 'i' };

  // Run in parallel for performance
  const [users, communities, resources] = await Promise.all([
    User.find({
      $or: [
        { name: query },
        { username: query },
        { college: query }
      ],
      isBanned: false
    })
    .select('name avatar username college role graduationYear campusScore')
    .sort({ campusScore: -1 })
    .limit(limit),

    Community.find({
      $or: [
        { name: query },
        { displayName: query }
      ],
      isActive: true
    })
    .select('name displayName avatar memberCount description college')
    .sort({ memberCount: -1 })
    .limit(limit),

    Resource.find({
      $or: [
        { title: query },
        { description: query },
        { tags: { $in: [new RegExp(q, 'i')] } }
      ]
    })
    .select('title category url author college downloadCount')
    .populate('author', 'name avatar')
    .sort({ downloadCount: -1, createdAt: -1 })
    .limit(limit)
  ]);

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Unified search results',
      data: {
        users,
        communities,
        resources
      }
    })
  );
});

export default {
  globalSearch
};

