  getFeed,
  getPostById,
  updatePost,
  deletePost,
  votePost,
  removeVote,
  getCommunityPosts,
  getUserPosts,
  uploadImages,
  votePoll
};

import Post from '../models/Post.model.js';
import { SORT_OPTIONS } from '../utils/constants.js';

/**
 * Calculate hot score using Reddit's hot algorithm
 * @param {Object} post - Post object
 * @returns {number} Hot score
 */
export const calculateHotScore = (post) => {
  const score = post.upvotes - post.downvotes;
  const order = Math.log10(Math.max(Math.abs(score), 1));
  const sign = score > 0 ? 1 : score < 0 ? -1 : 0;

  // Reddit's epoch (November 14, 2005)
  const epoch = 1134028003;
  const seconds = post.createdAt.getTime() / 1000 - epoch;

  return Math.round(sign * order + seconds / 45000);
};

/**
 * Calculate top score (pure vote count)
 * @param {Object} post - Post object
 * @returns {number} Top score
 */
export const calculateTopScore = (post) => {
  return post.upvotes - post.downvotes;
};

/**
 * Sort posts by specified criteria
 * @param {Array} posts - Array of posts
 * @param {string} sortType - Sort type ('hot', 'new', 'top')
 * @returns {Array} Sorted posts
 */
export const sortPosts = (posts, sortType = SORT_OPTIONS.HOT) => {
  const sortedPosts = [...posts];

  switch (sortType) {
    case SORT_OPTIONS.HOT:
      sortedPosts.sort((a, b) => b.hotScore - a.hotScore);
      break;
    case SORT_OPTIONS.NEW:
      sortedPosts.sort((a, b) => b.createdAt - a.createdAt);
      break;
    case SORT_OPTIONS.TOP:
      sortedPosts.sort((a, b) => b.score - a.score);
      break;
    default:
      sortedPosts.sort((a, b) => b.hotScore - a.hotScore);
  }

  return sortedPosts;
};

/**
 * Update hot scores for all posts
 * Useful for periodic recalculation
 * @returns {Promise<void>}
 */
export const updateAllHotScores = async () => {
  const posts = await Post.find({ isDeleted: false });

  for (const post of posts) {
    post.calculateHotScore();
    await post.save();
  }

  console.log(`Updated hot scores for ${posts.length} posts`);
};

/**
 * Get trending posts
 * @param {number} limit - Number of posts to return
 * @returns {Promise<Array>} Trending posts
 */
export const getTrendingPosts = async (limit = 10) => {
  const posts = await Post.find({ isDeleted: false })
    .sort({ hotScore: -1 })
    .limit(limit)
    .populate('author', 'name avatar')
    .populate('community', 'name displayName');

  return posts;
};

/**
 * Get top posts by time period
 * @param {string} period - Time period ('day', 'week', 'month', 'year', 'all')
 * @param {number} limit - Number of posts to return
 * @returns {Promise<Array>} Top posts
 */
export const getTopPostsByPeriod = async (period = 'all', limit = 10) => {
  let dateFilter = {};

  if (period !== 'all') {
    const now = new Date();
    let startDate;

    switch (period) {
      case 'day':
        startDate = new Date(now.setDate(now.getDate() - 1));
        break;
      case 'week':
        startDate = new Date(now.setDate(now.getDate() - 7));
        break;
      case 'month':
        startDate = new Date(now.setMonth(now.getMonth() - 1));
        break;
      case 'year':
        startDate = new Date(now.setFullYear(now.getFullYear() - 1));
        break;
    }

    dateFilter = { createdAt: { $gte: startDate } };
  }

  const posts = await Post.find({ isDeleted: false, ...dateFilter })
    .sort({ score: -1 })
    .limit(limit)
    .populate('author', 'name avatar')
    .populate('community', 'name displayName');

  return posts;
};

/**
 * Get recommended posts for user
 * @param {string} userId - User ID
 * @param {number} limit - Number of posts to return
 * @returns {Promise<Array>} Recommended posts
 */
export const getRecommendedPosts = async (userId, limit = 20) => {
  // Get user's communities
  const User = (await import('../models/User.model.js')).default;
  const user = await User.findById(userId).select('communities');

  if (!user || !user.communities.length) {
    // Return trending posts if user has no communities
    return getTrendingPosts(limit);
  }

  // Get posts from user's communities
  const posts = await Post.find({
    community: { $in: user.communities },
    isDeleted: false
  })
    .sort({ hotScore: -1 })
    .limit(limit)
    .populate('author', 'name avatar')
    .populate('community', 'name displayName');

  return posts;
};

export default {
  calculateHotScore,
  calculateTopScore,
  sortPosts,
  updateAllHotScores,
  getTrendingPosts,
  getTopPostsByPeriod,
  getRecommendedPosts
};

import Resource from '../models/Resource.model.js';
import User from '../models/User.model.js';
import { formatSuccess, formatError } from '../utils/formatResponse.js';
import { HTTP_STATUS } from '../utils/constants.js';
import { asyncHandler } from '../middleware/error.middleware.js';

/**
 * Create new resource
 * POST /api/resources
 */
export const createResource = asyncHandler(async (req, res) => {
  const { title, description, category, url, tags } = req.body;

  const user = await User.findById(req.userId);
  if (!user) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({ message: 'User not found', statusCode: HTTP_STATUS.NOT_FOUND })
    );
  }

  const resource = await Resource.create({
    title,
    description,
    category,
    url,
    tags,
    author: req.userId,
    college: user.college
  });

  await resource.populate('author', 'name avatar role graduationYear');

  res.status(HTTP_STATUS.CREATED).json(
    formatSuccess({
      message: 'Resource shared successfully',
      data: { resource }
    })
  );
});

/**
 * Get resources with filtering
 * GET /api/resources
 */
export const getResources = asyncHandler(async (req, res) => {
  const { category, search, college, page = 1, limit = 20 } = req.query;
  const skip = (page - 1) * limit;

  const query = {};
  if (category) query.category = category;
  if (college) query.college = college;
  if (search) {
    query.$or = [
      { title: { $regex: search, $options: 'i' } },
      { description: { $regex: search, $options: 'i' } },
      { tags: { $in: [new RegExp(search, 'i')] } }
    ];
  }

  const resources = await Resource.find(query)
    .sort({ createdAt: -1 })
    .skip(skip)
    .limit(limit)
    .populate('author', 'name avatar role graduationYear');

  const total = await Resource.countDocuments(query);

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Resources retrieved successfully',
      data: { resources },
      pagination: {
        total,
        page: Number(page),
        limit: Number(limit),
        totalPages: Math.ceil(total / limit),
        hasNextPage: page * limit < total
      }
    })
  );
});

/**
 * Delete resource
 * DELETE /api/resources/:id
 */
export const deleteResource = asyncHandler(async (req, res) => {
  const resource = await Resource.findById(req.params.id);

  if (!resource) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({ message: 'Resource not found', statusCode: HTTP_STATUS.NOT_FOUND })
    );
  }

  // Only author or admin can delete
  const isAdmin = req.user.role === 'admin';
  if (resource.author.toString() !== req.userId && !isAdmin) {
    return res.status(HTTP_STATUS.FORBIDDEN).json(
      formatError({ message: 'Unauthorized to delete this resource', statusCode: HTTP_STATUS.FORBIDDEN })
    );
  }

  await resource.deleteOne();

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Resource deleted successfully',
      data: null
    })
  );
});

/**
 * Increment download count
 * POST /api/resources/:id/download
 */
export const incrementDownload = asyncHandler(async (req, res) => {
  const resource = await Resource.findByIdAndUpdate(
    req.params.id,
    { $inc: { downloadCount: 1 } },
    { new: true }
  );

  if (!resource) {
    return res.status(HTTP_STATUS.NOT_FOUND).json(
      formatError({ message: 'Resource not found', statusCode: HTTP_STATUS.NOT_FOUND })
    );
  }

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'Download count incremented',
      data: { downloadCount: resource.downloadCount }
    })
  );
});

/**
 * Handle document upload and return its URL
 * POST /api/resources/upload
 */
export const uploadResourceFile = asyncHandler(async (req, res) => {
  if (!req.file) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({ message: 'No file uploaded', statusCode: HTTP_STATUS.BAD_REQUEST })
    );
  }

  const fileUrl = `/uploads/documents/${req.file.filename}`;

  res.status(HTTP_STATUS.OK).json(
    formatSuccess({
      message: 'File uploaded successfully',
      data: { url: fileUrl }
    })
  );
});

export default {
  createResource,
  getResources,
  deleteResource,
  incrementDownload,
  uploadResourceFile
};

