import Post from '../models/Post.model.js';
import Comment from '../models/Comment.model.js';
import User from '../models/User.model.js';
import { CAMPUS_SCORE_WEIGHTS } from './constants.js';

/**
 * Calculate campus score for a user based on their activity
 * @param {string} userId - User ID
 * @returns {Promise<number>} Calculated campus score
 */
export const calculateCampusScore = async (userId) => {
  try {
    // Get all posts by user with their upvotes
    const posts = await Post.find({ 
      author: userId, 
      isDeleted: false 
    }).select('upvotes');

    // Get all comments by user with their upvotes
    const comments = await Comment.find({ 
      author: userId, 
      isDeleted: false 
    }).select('upvotes');

    // Calculate score from post upvotes
    const postUpvoteScore = posts.reduce((sum, post) => {
      return sum + (post.upvotes * CAMPUS_SCORE_WEIGHTS.POST_UPVOTE);
    }, 0);

    // Calculate score from comment upvotes
    const commentUpvoteScore = comments.reduce((sum, comment) => {
      return sum + (comment.upvotes * CAMPUS_SCORE_WEIGHTS.COMMENT_UPVOTE);
    }, 0);

    // Calculate score from content creation
    const postCreationScore = posts.length * CAMPUS_SCORE_WEIGHTS.POST_CREATED;
    const commentCreationScore = comments.length * CAMPUS_SCORE_WEIGHTS.COMMENT_CREATED;

    // Total score
    const totalScore = postUpvoteScore + commentUpvoteScore + postCreationScore + commentCreationScore;

    return totalScore;
  } catch (error) {
    console.error('Error calculating campus score:', error);
    throw error;
  }
};

/**
 * Update user's campus score in database
 * @param {string} userId - User ID
 * @returns {Promise<Object>} Updated user object
 */
export const updateCampusScore = async (userId) => {
  try {
    const score = await calculateCampusScore(userId);

    const user = await User.findByIdAndUpdate(
      userId,
      { campusScore: score },
      { new: true }
    );

    return user;
  } catch (error) {
    console.error('Error updating campus score:', error);
    throw error;
  }
};

/**
 * Recalculate campus score for all users
 * Useful for periodic updates or maintenance
 * @returns {Promise<void>}
 */
export const recalculateAllCampusScores = async () => {
  try {
    const users = await User.find({}).select('_id');

    for (const user of users) {
      await updateCampusScore(user._id);
    }

    console.log(`Recalculated campus scores for ${users.length} users`);
  } catch (error) {
    console.error('Error recalculating all campus scores:', error);
    throw error;
  }
};

/**
 * Get leaderboard of users by campus score
 * @param {Object} options - Options for leaderboard
 * @returns {Promise<Array>} Array of users sorted by campus score
 */
export const getLeaderboard = async ({ limit = 10, college = null } = {}) => {
  try {
    const query = { isBanned: false };
    if (college) {
      query.college = college;
    }

    const users = await User.find(query)
      .select('name avatar college campusScore role graduationYear')
      .sort({ campusScore: -1 })
      .limit(limit);

    return users;
  } catch (error) {
    console.error('Error getting leaderboard:', error);
    throw error;
  }
};

export default {
  calculateCampusScore,
  updateCampusScore,
  recalculateAllCampusScores,
  getLeaderboard
};

import { createContext, useState, useContext, useEffect, useCallback, useRef } from 'react';
import api from '../services/api';
import { toast } from 'react-hot-toast';

const PostContext = createContext();

export const usePosts = () => useContext(PostContext);

export const PostProvider = ({ children }) => {
    const [posts, setPosts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [sortBy, setSortBy] = useState('hot');
    const [page, setPage] = useState(1);
    const [hasMore, setHasMore] = useState(true);
    const postsRef = useRef(posts);
    postsRef.current = posts;

    const fetchPosts = useCallback(async (pageNum = 1, reset = false) => {
        if (loading && pageNum !== 1) return; // Prevent concurrent page loads

        if (reset || pageNum === 1) {
            setLoading(true);
        }

        try {
            const response = await api.get(`/posts?sort=${sortBy}&page=${pageNum}`);
            const newPosts = response.data.data.posts;

            setPosts(prev => reset || pageNum === 1 ? newPosts : [...prev, ...newPosts]);
            setHasMore(response.data.pagination?.hasNextPage || false);
            setPage(pageNum);
        } catch (error) {
            console.error('Failed to fetch posts:', error);
            toast.error('Failed to load feed');
        } finally {
            setLoading(false);
        }
    }, [sortBy, loading]);

    useEffect(() => {
        setPage(1);
        fetchPosts(1, true);
    }, [sortBy]);

    const loadMore = useCallback(() => {
        if (loading || !hasMore) return;
        const nextPage = page + 1;
        fetchPosts(nextPage, false);
    }, [page, fetchPosts, loading, hasMore]);

    const vote = async (postId, type) => {
        const currentPosts = postsRef.current;
        const post = currentPosts.find(p => p._id === postId);
        if (!post) return;

        const currentVote = post.userVote || 0;
        let newVote;
        if (type === 'up') {
            newVote = currentVote === 1 ? 0 : 1;
        } else {
            newVote = currentVote === -1 ? 0 : -1;
        }
        const scoreChange = newVote - currentVote;

        // Optimistic update
        setPosts(prevPosts => prevPosts.map(p => {
            if (p._id === postId) {
                return { ...p, userVote: newVote, score: (p.score || 0) + scoreChange };
            }
            return p;
        }));

        try {
            if (newVote === 0) {
                await api.delete(`/posts/${postId}/vote`);
            } else {
                await api.post(`/posts/${postId}/vote`, { value: newVote });
            }
        } catch (error) {
            console.error('Vote failed:', error);
            toast.error('Vote failed');
            // Revert on failure
            setPosts(prevPosts => prevPosts.map(p => {
                if (p._id === postId) {
                    return { ...p, userVote: currentVote, score: (p.score || 0) - scoreChange };
                }
                return p;
            }));
        }
    };

    const createPost = async (postData) => {
        try {
            const response = await api.post('/posts', postData);
            setPosts(prev => [response.data.data.post, ...prev]);
            toast.success('Post created!');
            return response.data.data.post;
        } catch (error) {
            console.error('Create post failed:', error);
            throw error;
        }
    };

    return (
        <PostContext.Provider value={{ posts, loading, vote, createPost, setSortBy, sortBy, fetchPosts, hasMore, loadMore }}>
            {children}
        </PostContext.Provider>
    );
};

