import { createContext, useState, useContext, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-hot-toast';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [token, setToken] = useState(localStorage.getItem('token'));
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        checkAuth();
    }, []);

    const checkAuth = async () => {
        const storedToken = localStorage.getItem('token');
        if (!storedToken) {
            try {
                const response = await api.post('/auth/guest');
                const { accessToken, user: userData } = response.data.data;

                localStorage.setItem('token', accessToken);
                localStorage.setItem('user', JSON.stringify(userData));
                setUser(userData);
                setToken(accessToken);
            } catch (error) {
                console.error('Guest login failed:', error);
            } finally {
                setLoading(false);
            }
            return;
        }
        setToken(storedToken);

        try {
            const response = await api.get('/users/profile/me');
            setUser(response.data.data.user);
        } catch (error) {
            console.error('Auth check failed:', error);
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            setUser(null);
            setToken(null);
        } finally {
            setLoading(false);
        }
    };

    const login = async (email, password) => {
        try {
            const response = await api.post('/auth/login', { email, password });
            const { accessToken, user: userData } = response.data.data;

            localStorage.setItem('token', accessToken);
            localStorage.setItem('user', JSON.stringify(userData));
            setUser(userData);
            setToken(accessToken);

            toast.success(`Welcome back, ${userData.name}!`);
            return userData;
        } catch (error) {
            const message = error.response?.data?.errors?.[0]?.message || error.response?.data?.message || 'Login failed';
            toast.error(message);
            throw message;
        }
    };

    const logout = () => {
        setUser(null);
        setToken(null);
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        toast.success('Logged out successfully');
        window.location.href = '/login';
    };

    const register = async (userData) => {
        try {
            const response = await api.post('/auth/register', userData);
            const { accessToken, user: newUser } = response.data.data;

            localStorage.setItem('token', accessToken);
            localStorage.setItem('user', JSON.stringify(newUser));
            setUser(newUser);
            setToken(accessToken);

            toast.success('Account created! Welcome to the campus.');
            return newUser;
        } catch (error) {
            const message = error.response?.data?.errors?.[0]?.message || error.response?.data?.message || 'Registration failed';
            toast.error(message);
            throw message;
        }
    };

    return (
        <AuthContext.Provider value={{ user, token, login, logout, register, loading, checkAuth }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

import { body, validationResult } from 'express-validator';
import { REGEX } from '../utils/constants.js';
import { formatError } from '../utils/formatResponse.js';
import { HTTP_STATUS } from '../utils/constants.js';

/**
 * Handle validation errors
 */
const handleValidationErrors = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(HTTP_STATUS.BAD_REQUEST).json(
      formatError({
        message: 'Validation failed',
        errors: errors.array().map(err => ({
          field: err.path,
          message: err.msg
        })),
        statusCode: HTTP_STATUS.BAD_REQUEST
      })
    );
  }
  next();
};

/**
 * Validate community creation
 */
export const validateCommunity = [
  body('name')
    .trim()
    .notEmpty()
    .withMessage('Community name is required')
    .matches(REGEX.COMMUNITY_NAME)
    .withMessage('Community name must be 3-30 characters, alphanumeric with hyphens only')
    .toLowerCase(),

  body('displayName')
    .trim()
    .notEmpty()
    .withMessage('Display name is required')
    .isLength({ max: 100 })
    .withMessage('Display name cannot exceed 100 characters'),

  body('description')
    .trim()
    .notEmpty()
    .withMessage('Description is required')
    .isLength({ max: 1000 })
    .withMessage('Description cannot exceed 1000 characters'),

  body('college')
    .trim()
    .notEmpty()
    .withMessage('College name is required')
    .isLength({ max: 200 })
    .withMessage('College name cannot exceed 200 characters'),

  body('rules')
    .optional()
    .isArray()
    .withMessage('Rules must be an array')
    .custom((rules) => {
      if (rules && rules.length > 0) {
        rules.forEach((rule, index) => {
          if (typeof rule !== 'string') {
            throw new Error(`Rule ${index + 1} must be a string`);
          }
          if (rule.length > 500) {
            throw new Error(`Rule ${index + 1} cannot exceed 500 characters`);
          }
        });
      }
      return true;
    }),

  handleValidationErrors
];

